import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { streamxApi } from '../services/api';

export default function ProfilePage() {
  const { user } = useAuth();
  const [subscription, setSubscription] = useState(null);

  useEffect(() => {
    streamxApi.getMySubscription()
      .then((res) => setSubscription(res.data))
      .catch(() => setSubscription(null));
  }, []);

  return (
    <main style={{ paddingTop: '96px', padding: '96px 24px 24px' }}>
      <h1 style={{ marginBottom: '16px' }}>My Profile</h1>
      <div style={{ background: '#121212', border: '1px solid #282828', borderRadius: '12px', padding: '16px', maxWidth: '720px' }}>
        <p><strong>Name:</strong> {user?.name || user?.username}</p>
        <p><strong>Email:</strong> {user?.email}</p>
        <p><strong>Role:</strong> {user?.role || 'user'}</p>
        <p><strong>Plan:</strong> {subscription?.plan || user?.plan || 'free'}</p>
      </div>
    </main>
  );
}
